function pickGifts(gifts: number[], k: number): number {
    const pq = new MaxPriorityQueue<number>();
    gifts.forEach(v => pq.enqueue(v));
    while (k--) {
        let v = pq.dequeue();
        v = Math.floor(Math.sqrt(v));
        pq.enqueue(v);
    }
    let ans = 0;
    while (!pq.isEmpty()) {
        ans += pq.dequeue();
    }
    return ans;
}

